import{_ as a,c as i,o as l,a1 as r}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"进阶：流水线与内部机制 | AI App Factory 教程","description":"深入了解 AI App Factory 的 7 阶段流水线、Sisyphus 调度器、权限安全机制和失败处理策略。掌握上下文优化与高级配置技巧。","frontmatter":{"title":"进阶：流水线与内部机制 | AI App Factory 教程","sidebarTitle":"进阶：流水线","subtitle":"进阶：流水线与内部机制","description":"深入了解 AI App Factory 的 7 阶段流水线、Sisyphus 调度器、权限安全机制和失败处理策略。掌握上下文优化与高级配置技巧。","tags":["流水线","调度器","权限安全","失败处理"],"prerequisite":["start-pipeline-overview"],"order":80},"headers":[],"relativePath":"zh/hyz1992/agent-app-factory/advanced/index.md","filePath":"zh/hyz1992/agent-app-factory/advanced/index.md"}'),e={name:"zh/hyz1992/agent-app-factory/advanced/index.md"};function o(s,t,n,p,d,h){return l(),i("div",null,[...t[0]||(t[0]=[r('<h1 id="进阶-流水线与内部机制" tabindex="-1">进阶：流水线与内部机制 <a class="header-anchor" href="#进阶-流水线与内部机制" aria-label="Permalink to &quot;进阶：流水线与内部机制&quot;">​</a></h1><p>本章节深入讲解 AI App Factory 的核心机制和高级功能，包括 7 阶段流水线的详细工作原理、Sisyphus 调度器的调度策略、权限与安全机制、失败处理策略，以及如何通过上下文优化节省 Token 成本。</p><div class="warning custom-block"><p class="custom-block-title">前置条件</p><p>学习本章节前，请确保已完成：</p><ul><li><a href="./../../start/getting-started/">快速开始</a> 和 <a href="./../../start/installation/">安装配置</a></li><li><a href="./../../start/pipeline-overview/">7 阶段流水线概览</a></li><li><a href="./../../platforms/claude-code/">平台集成</a> 配置</li></ul></div><h2 id="章节内容" tabindex="-1">章节内容 <a class="header-anchor" href="#章节内容" aria-label="Permalink to &quot;章节内容&quot;">​</a></h2><p>本章节包含以下主题：</p><h3 id="_7-阶段流水线详解" tabindex="-1">7 阶段流水线详解 <a class="header-anchor" href="#_7-阶段流水线详解" aria-label="Permalink to &quot;7 阶段流水线详解&quot;">​</a></h3><ul><li><p><strong><a href="./stage-bootstrap/">阶段 1：Bootstrap - 结构化产品想法</a></strong></p><ul><li>学习如何将模糊的产品想法转化为结构化文档</li><li>理解 Bootstrap Agent 的输入输出格式</li></ul></li><li><p><strong><a href="./stage-prd/">阶段 2：PRD - 生成产品需求文档</a></strong></p><ul><li>生成 MVP 级 PRD，包含用户故事、功能列表和非目标</li><li>掌握需求分解和优先级排序技巧</li></ul></li><li><p><strong><a href="./stage-ui/">阶段 3：UI - 设计界面与原型</a></strong></p><ul><li>使用 ui-ux-pro-max 技能设计 UI 结构和可预览原型</li><li>理解界面设计流程和最佳实践</li></ul></li><li><p><strong><a href="./stage-tech/">阶段 4：Tech - 设计技术架构</a></strong></p><ul><li>设计最小可行的技术架构和 Prisma 数据模型</li><li>掌握技术选型和架构设计原则</li></ul></li><li><p><strong><a href="./stage-code/">阶段 5：Code - 生成可运行代码</a></strong></p><ul><li>根据 UI Schema 和 Tech 设计生成前后端代码、测试和配置</li><li>理解代码生成流程和模板系统</li></ul></li><li><p><strong><a href="./stage-validation/">阶段 6：Validation - 验证代码质量</a></strong></p><ul><li>验证依赖安装、类型检查、Prisma schema 和代码质量</li><li>掌握自动化质量检查流程</li></ul></li><li><p><strong><a href="./stage-preview/">阶段 7：Preview - 生成部署指南</a></strong></p><ul><li>生成完整的运行说明文档和部署配置</li><li>学习 CI/CD 集成和 Git Hooks 配置</li></ul></li></ul><h3 id="内部机制" tabindex="-1">内部机制 <a class="header-anchor" href="#内部机制" aria-label="Permalink to &quot;内部机制&quot;">​</a></h3><ul><li><p><strong><a href="./orchestrator/">Sisyphus 调度器详解</a></strong></p><ul><li>理解调度器如何协调流水线、管理状态和执行权限检查</li><li>掌握调度策略和状态机原理</li></ul></li><li><p><strong><a href="./context-optimization/">上下文优化：分会话执行</a></strong></p><ul><li>学习如何使用 <code>factory continue</code> 命令节省 Token</li><li>掌握在每个阶段新建会话的最佳实践</li></ul></li><li><p><strong><a href="./security-permissions/">权限与安全机制</a></strong></p><ul><li>理解能力边界矩阵、越权处理和安全检查机制</li><li>掌握安全配置和权限管理</li></ul></li><li><p><strong><a href="./failure-handling/">失败处理与回滚</a></strong></p><ul><li>学习失败识别、重试机制、回滚策略和人工介入流程</li><li>掌握故障排查和恢复技巧</li></ul></li></ul><h2 id="学习路径建议" tabindex="-1">学习路径建议 <a class="header-anchor" href="#学习路径建议" aria-label="Permalink to &quot;学习路径建议&quot;">​</a></h2><h3 id="推荐学习顺序" tabindex="-1">推荐学习顺序 <a class="header-anchor" href="#推荐学习顺序" aria-label="Permalink to &quot;推荐学习顺序&quot;">​</a></h3><ol><li><p><strong>先学完 7 阶段流水线</strong>（按顺序）</p><ul><li>Bootstrap → PRD → UI → Tech → Code → Validation → Preview</li><li>每个阶段都有明确的输入输出，按顺序学习能建立完整的认知</li></ul></li><li><p><strong>再学习调度器和上下文优化</strong></p><ul><li>理解 Sisyphus 如何协调这 7 个阶段</li><li>学习如何优化上下文以节省 Token 成本</li></ul></li><li><p><strong>最后学习安全与失败处理</strong></p><ul><li>掌握权限边界和安全机制</li><li>了解失败场景和应对策略</li></ul></li></ol><h3 id="不同角色的学习重点" tabindex="-1">不同角色的学习重点 <a class="header-anchor" href="#不同角色的学习重点" aria-label="Permalink to &quot;不同角色的学习重点&quot;">​</a></h3><table tabindex="0"><thead><tr><th>角色</th><th>重点学习章节</th></tr></thead><tbody><tr><td><strong>开发者</strong></td><td>Code、Validation、Tech、Orchestrator</td></tr><tr><td><strong>产品经理</strong></td><td>Bootstrap、PRD、UI、Preview</td></tr><tr><td><strong>技术负责人</strong></td><td>Tech、Code、Security、Failure Handling</td></tr><tr><td><strong>DevOps 工程师</strong></td><td>Validation、Preview、Context Optimization</td></tr></tbody></table><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>完成本章节后，你可以继续学习：</p><ul><li><strong><a href="./../../faq/troubleshooting/">常见问题与故障排除</a></strong> - 解决实际使用中的问题</li><li><strong><a href="./../../faq/best-practices/">最佳实践</a></strong> - 掌握高效使用 Factory 的技巧</li><li><strong><a href="./../../appendix/cli-commands/">CLI 命令参考</a></strong> - 查看完整的命令列表</li><li><strong><a href="./../../appendix/code-standards/">代码规范</a></strong> - 了解生成的代码应遵循的规范</li></ul><hr><p>💡 <strong>提示</strong>：如果在使用过程中遇到问题，请先查看 <a href="./../../faq/troubleshooting/">常见问题与故障排除</a> 章节。</p>',19)])])}const g=a(e,[["render",o]]);export{c as __pageData,g as default};
